{"rawEvent":{"message_id":"019e9a83b828760da1e3a0c3a7477555","conversation_id":"019e97004e85717aa3c2aff8ca9e1419","tool_call_id":"tooluse_qvZW4CpizuYg7vbV0sD92Z","document":{"file_path":"/home/ubuntu/Desktop/JW/vm_iot/tests/test_config.cpp","sub_content":"test_config.cpp","sub_content_event":"open_editor","sub_content_event_value":"/home/ubuntu/Desktop/JW/vm_iot/tests/test_config.cpp","sub_content_tip":"/home/ubuntu/Desktop/JW/vm_iot/tests/test_config.cpp","apply_content":"//
// Created by vompom on 2026/06/06.
//
// @Description
// 单元测试：验证 Config 各子结构的默认值是否符合预期。
// 仅用 <cassert>，不引入额外测试框架，便于零依赖快速验证。
//

#include <cassert>
#include <cstdio>
#include <string>

#include "config.h"

static void test_server_config_defaults() {
 ServerConfig s;
 assert(s.port == 8554);
