{"rawEvent":{"message_id":"019e9f5e8686799c84dfc09088bbf478","conversation_id":"019e97004e85717aa3c2aff8ca9e1419","tool_call_id":"tooluse_ltW9L9GgLDHrA842ik2Mtn","document":{"file_path":"/home/ubuntu/Desktop/JW/vm_iot/src/app/signal_handler.cpp","sub_content":"signal_handler.cpp","sub_content_event":"open_editor","sub_content_event_value":"/home/ubuntu/Desktop/JW/vm_iot/src/app/signal_handler.cpp","sub_content_tip":"/home/ubuntu/Desktop/JW/vm_iot/src/app/signal_handler.cpp","apply_content":"//
// Created by vompom on on 2026/06/06 09:20.
//
// @Description
// 把 POSIX 信号 (SIGINT / SIGTERM) 接入 GLib 主循环，让进程能"优雅退出"：
// 收到信号时只是请求主循环 quit，由主循环正常返回到 main()，
// 再按顺序释放 RTSP 服务器、GMainLoop 等资源，避免资源泄漏 / 端口未释放。
//
// 实现要点：
// - 使用 g_unix_signal_add 而不是 POSIX 的 signal() / sigaction()。
// 原因：传统信号处理器运行在"信号上下文"里，能调用的函数必须是
// async-signal-safe 的（清单见 signal-safety(7)），
// 而 g_main_loop_quit / spdlog / new / malloc 等几乎都不安全。
// g_unix_signal_add 内部用管道 + GSource 把信号"搬运"到主循环线程，
// 回调在主循环上下文里执行，可以安全地做任意事情。
//

#include "signal_handler.h"
#include "log.h"
#include <glib-unix.h> // g_unix_signal_add 所在头文件 (Linux/Unix 专用)


// 信号回调：在主循环上下文中被调用，不在信号上下文中。
// 签名由 GLib 规定 —— GSourceFunc：gboolean (*)(gpointer)。
// user: 注册时通过 g_unix_signal_add 透传的用户数据，这里就是 GMainLoop*。
// 返回值语义：
// G_SOURCE_REMOVE (FALSE) —— 一次性，处理完就把这个 source 从主循环摘掉；
// G_SOURCE_CONTINUE(TRUE) —— 保留，之后还会继续触发。
// 这里只需响应一次即可，所以返回 G_SOURCE_REMOVE。
static gboolean on_term(gpointer user) {
 auto *loop = static_cast<GMainLoop *>(user);
 LOGI("signal received, quitting main loop");
 // 请求主循环退出；此调用线程安全，且只是设置退出标记，
 // 真正的"返回 main()"发生在 g_main_loop_run() 内部的下一轮 iteration。
 g_main_loop_quit(loop);
 return G_SOURCE_REMOVE;
}

// 注册 SIGINT (Ctrl+C) 与 SIGTERM (kill 默认信号) 的处理。
// 注意没注册 SIGKILL / SIGSTOP —— 这两个内核不允许捕获，进程会被强杀，
// 也就没机会做清理；这是操作系统设计，不是 bug。
void install_signals(GMainLoop *loop) {
 // g_unix_signal_add(signum, callback, user_data):
 // - 在内部创建一个 GSource 挂到默认 GMainContext；
 // - 当对应信号到达时，由 GLib 的信号管道把它转发到主循环；
 // - 回调在 g_main_loop_run() 所在的线程被调用，避免信号上下文限制。
 // 返回值是 source id，可用于 g_source_remove 取消；本程序进程级一次性注册，
 // 不需要保存。
 g_unix_signal_add(SIGINT, on_term, loop);
 g_unix_signal_add(SIGTERM, on_term, loop);
}
